#include<iostream>#include<vector>#include<algorithm>#include<climits>#define ll long longusing namespace std;bool same_parity(ll a,ll b){    return (abs(a)%2==abs(b)%2);}int main(){    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll> a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }                ll sum=a[0];        ll max_sum=a[0];        for(int i=1;i<n;i++){            if(same_parity(a[i],a[i-1])){                sum= a[i];            }            else{                sum=max(sum+a[i],a[i]);            }            max_sum=max(max_sum,sum);        }        cout<<max_sum<<endl;    }}